<?php use App\Core\Helpers as H;?><section class="panel narrow"><h1>Join the Asset Moth launch waitlist</h1><p>By signing up, you consent to receive your confirmation and Asset Moth launch communication. You can unsubscribe at any time.</p>
<?php if($success):?><div class="notice success">Thanks! If this address is eligible, your waitlist preferences have been saved.</div><?php else:?><?php foreach($errors as $e):?><div class="notice warning"><?=H::e($e)?></div><?php endforeach;?><form method="post"><input type="hidden" name="_csrf" value="<?=H::csrf()?>"><label>Name<input required maxlength="120" name="name" value="<?=H::e($values['name'])?>"></label><label>Email<input required maxlength="190" type="email" name="email" value="<?=H::e($values['email'])?>"></label><label>I am interested as<select name="interest_type"><?php foreach(['seller'=>'Seller','buyer'=>'Buyer','both'=>'Both','tester'=>'Tester'] as $k=>$v):?><option value="<?=$k?>" <?=$values['interest_type']===$k?'selected':''?>><?=$v?></option><?php endforeach;?></select></label><label>Business name (optional)<input maxlength="190" name="business_name" value="<?=H::e($values['business_name'])?>"></label><input type="hidden" name="source" value="<?=H::e($values['source'])?>"><div class="hp" aria-hidden="true"><label>Website<input tabindex="-1" autocomplete="off" name="website"></label></div><button class="btn">Join waitlist</button></form><?php endif;?></section>
